cat << 'EOF' > /tmp/analyze_binlog.cs
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);
        var errors = new List<(string project, string code, string message, string file, int line)>();

        build.VisitAllChildren<Error>(error => {
            var project = GetParentProject(error);
            errors.Add((project, error.Code ?? "", error.Message ?? "", error.File ?? "", error.LineNumber));
        });

        Console.WriteLine($"Total errors: {errors.Count}");
        Console.WriteLine();

        // Group by project
        var byProject = errors.GroupBy(e => e.project).OrderBy(g => g.Key);
        foreach (var group in byProject)
        {
            Console.WriteLine($"=== Project: {group.Key} ===");
            foreach (var e in group)
            {
                Console.WriteLine($"  [{e.code}] {e.file}({e.line}): {e.message}");
            }
            Console.WriteLine();
        }

        // Also show warnings that might be relevant
        var warnings = new List<(string project, string code, string message)>();
        build.VisitAllChildren<Warning>(w => {
            var project = GetParentProject(w);
            warnings.Add((project, w.Code ?? "", w.Message ?? ""));
        });

        if (warnings.Any(w => w.code.StartsWith("NU") || w.code == "MSB3245"))
        {
            Console.WriteLine("=== Relevant Warnings ===");
            foreach (var w in warnings.Where(w => w.code.StartsWith("NU") || w.code == "MSB3245"))
            {
                Console.WriteLine($"  [{w.code}] ({w.project}): {w.message}");
            }
        }
    }

    static string GetParentProject(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p.Name ?? "unknown";
            if (current is Target t && t.Parent is Project tp) return tp.Name ?? "unknown";
            current = current.Parent;
        }
        return "unknown";
    }
}
EOF
